    const map = window.activeElements;
    if (!map || typeof map.entries !== 'function') return [];
    return [...map.entries()]
      .filter(([id, element]) => isMixable(id, element))
      .sort((a, b) => String(a[1]?.layout?.x ?? 0) - String(b[1]?.layout?.x ?? 0));
